#nullable enable // autogenerated

using MVZ2.Vanilla.Enemies;
using MVZ2.Vanilla.Entities;

using MVZ2Logic.Entities;

using PVZEngine.Buffs;
using PVZEngine.Definitions;
using PVZEngine.Entities;
using PVZEngine.Modifiers;

using UnityEngine;

namespace MVZ2.GameContent.Buffs.Entities
{

    [AutoBuffDefinition(VanillaBuffNames.Entity.stoneEyeSlowing)]
    public class StoneEyeSlowingBuff : BuffDefinition
    {
        public StoneEyeSlowingBuff(string nsp, string name) : base(nsp, name)
        {
            AddModifier(new FloatModifier(VanillaEnemyProps.SPEED, NumberOperator.Multiply, 0.5f));
            AddModifier(new FloatModifier(VanillaEntityProps.ATTACK_SPEED, NumberOperator.Multiply, 0.5f));
            AddModifier(new Vector3Modifier(LogicEntityProps.HSV_OFFSET, NumberOperator.Add, new Vector3(0, -50, 0)) { NoStack = true });
            var tintModifier = ColorModifier.Multiply(EngineEntityProps.TINT, new Color(1.05f, 1.1f, 1.05f, 1f));
            tintModifier.NoStack = true;
            AddModifier(tintModifier);
        }
    }
}
